"""
This module defines the GameBoard class representing the 8x8 checkers board.
"""

class GameBoard:
    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in (1, 3, 5, 7):
                if (i + j) % 2 == 0:
                    self.board[i][j] = 'R'
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                if (i + j) % 2 == 1:
                    self.board[i][j] = 'B'

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    def move_piece(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        if (x2 - x1) ** 2 + (y2 - y1) ** 2 != 2:
            raise ValueError("Invalid move")
        self.board[x2][y2] = self.board[x1][y1]
        self.board[x1][y1] = ' '

    def is_valid_move(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        if abs(x1 - x2) != 2 or abs(y1 - y2) != 2:
            return False
        if (x2 + y2) % 2 == (x1 + y1) % 2:
            return False
        if self.board[x2][y2] != ' ':
            return False
        return True

# Example usage
if __name__ == "__main__":
    board = GameBoard()
    board.print_board()
```

